class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

def insert(root, char):
    if root is None:
        return Node(char)
    if char < root.value:
        root.left = insert(root.left, char)
    elif char > root.value:
        root.right = insert(root.right, char)
    return root

def process_sequence_recursive(sequence, index, root, seen):
    if index >= len(sequence):
        return root

    char = sequence[index].lower()
    if char not in seen:
        seen.add(char)
        root = insert(root, char)

    return process_sequence_recursive(sequence, index + 1, root, seen)

